1247: static void azx_init_pci(struct azx *chip)
1248: {
1249: 	/* Clear bits 0-2 of PCI register TCSEL (at offset 0x44)
1250: 	 * TCSEL == Traffic Class Select Register, which sets PCI express QOS
1251: 	 * Ensuring these bits are 0 clears playback static on some HD Audio
1252: 	 * codecs.
1253: 	 * The PCI register TCSEL is defined in the Intel manuals.
1254: 	 */
1255: 	if (!(chip->driver_caps & AZX_DCAPS_NO_TCSEL)) {
1256: 		snd_printdd(SFX "Clearing TCSEL\n");
1257: 		update_pci_byte(chip->pci, ICH6_PCIREG_TCSEL, 0x07, 0);
1258: 	}
1259: 
1260: 	/* For ATI SB450/600/700/800/900 and AMD Hudson azalia HD audio,
1261: 	 * we need to enable snoop.
1262: 	 */
1263: 	if (chip->driver_caps & AZX_DCAPS_ATI_SNOOP) {
1264: 		snd_printdd(SFX "Setting ATI snoop: %d\n", azx_snoop(chip));
1265: 		update_pci_byte(chip->pci,
1266: 				ATI_SB450_HDAUDIO_MISC_CNTR2_ADDR, 0x07,
1267: 				azx_snoop(chip) ? ATI_SB450_HDAUDIO_ENABLE_SNOOP : 0);
1268: 	}
1269: 
1270: 	/* For NVIDIA HDA, enable snoop */
1271: 	if (chip->driver_caps & AZX_DCAPS_NVIDIA_SNOOP) {
1272: 		snd_printdd(SFX "Setting Nvidia snoop: %d\n", azx_snoop(chip));
1273: 		update_pci_byte(chip->pci,
1274: 				NVIDIA_HDA_TRANSREG_ADDR,
1275: 				0x0f, NVIDIA_HDA_ENABLE_COHBITS);
1276: 		update_pci_byte(chip->pci,
1277: 				NVIDIA_HDA_ISTRM_COH,
1278: 				0x01, NVIDIA_HDA_ENABLE_COHBIT);
1279: 		update_pci_byte(chip->pci,
1280: 				NVIDIA_HDA_OSTRM_COH,
1281: 				0x01, NVIDIA_HDA_ENABLE_COHBIT);
1282: 	}
1283: 
1284: 	/* Enable SCH/PCH snoop if needed */
1285: 	if (chip->driver_caps & AZX_DCAPS_SCH_SNOOP) {
1286: 		unsigned short snoop;
1287: 		pci_read_config_word(chip->pci, INTEL_SCH_HDA_DEVC, &snoop);
1288: 		if ((!azx_snoop(chip) && !(snoop & INTEL_SCH_HDA_DEVC_NOSNOOP)) ||
1289: 		    (azx_snoop(chip) && (snoop & INTEL_SCH_HDA_DEVC_NOSNOOP))) {
1290: 			snoop &= ~INTEL_SCH_HDA_DEVC_NOSNOOP;
1291: 			if (!azx_snoop(chip))
1292: 				snoop |= INTEL_SCH_HDA_DEVC_NOSNOOP;
1293: 			pci_write_config_word(chip->pci, INTEL_SCH_HDA_DEVC, snoop);
1294: 			pci_read_config_word(chip->pci,
1295: 				INTEL_SCH_HDA_DEVC, &snoop);
1296: 		}
1297: 		snd_printdd(SFX "SCH snoop: %s\n",
1298: 				(snoop & INTEL_SCH_HDA_DEVC_NOSNOOP)
1299: 				? "Disabled" : "Enabled");
